create table Mitarbeiter (
  MitarbeiterNr  integer  not null primary key
);

create table Restaurant (
  RestaurantNr   integer  not null primary key
  -- NOT NULL weil Restaurant vollständig teilnimmt (min=1)
  -- UNIQUE weil 1:1: jeder Mitarbeiter höchstens ein Restaurant
, MitarbeiterNr  integer  not null unique references Mitarbeiter
);

create table Angestellter (
  SVN     varchar(10)  not null primary key
);

create table Filiale (
  FilialNr   integer      not null primary key
, LeiterSVN  varchar(10)  not null unique references Angestellter(SVN)
);

-- A(1,n) --- ab --- (0,1) B
-- max_A=n, max_B=1 → 1:n. FK in B (max=1). min_B=0 → nullable.

create table A (
  A_ID  integer  not null primary key
);

create table B (
  B_ID  integer  not null primary key
, A_ID  integer  references A   -- nullable, kein UNIQUE
);

create table Abteilung (
  AbtNr   integer      not null primary key
);

create table Angestellter (
  SVN     varchar(10)   not null primary key
, AbtNr   integer       not null references Abteilung
);

create table l (
  lnr    varchar(2)   not null primary key
, lname  varchar(6)   not null
);

create table t (
  tnr    varchar(2)   not null primary key
, tname  varchar(8)   not null
, preis  decimal(4,2) not null
);

create table lt (
  lnr    varchar(2)  not null references l
, tnr    varchar(2)  not null references t
, menge  decimal(4)  not null check(menge > 0)   -- Beziehungsattribut
, primary key (lnr, tnr)
);

create table untersteht (
  SVN        varchar(10)  not null references Angestellter  -- Untergebener
, LeiterSVN  varchar(10)  not null references Angestellter  -- Vorgesetzter
, primary key (SVN, LeiterSVN)
);

create table Kino (
  KinoNr  integer      not null primary key
);

create table Saal (
  KinoNr  integer  not null references Kino   -- FK = Teil des PK
, SaalNr  integer  not null                   -- Teilschlüssel
, primary key (KinoNr, SaalNr)
);

create table Vorstellung (
  KinoNr           integer   not null
, SaalNr           integer   not null
, Beginnzeitpunkt  datetime  not null
, primary key (KinoNr, SaalNr, Beginnzeitpunkt)
, foreign key (KinoNr, SaalNr) references Saal(KinoNr, SaalNr)
);

create table Tisch (
  FilialNr  integer  not null references Filiale   -- FK = Teil des PK
, TischNr   integer  not null                      -- Teilschlüssel
, Plaetze   integer  not null
, primary key (FilialNr, TischNr)
);

create table Raum (
  GebaeudNr  integer  not null references Gebaeude   -- FK = Teil des PK
, RaumNr     integer  not null                       -- Teilschlüssel
, primary key (GebaeudNr, RaumNr)
);

-- Schlägt fehl: mehrere rote Teile (12, 14, 19)
select * from t
 where preis > (select preis from t where farbe = 'rot');

-- Korrekt mit MAX:
select * from t
 where preis > (select max(preis) from t where farbe = 'rot');

-- Korrekt mit ALL:
select * from t
 where preis > all (select preis from t where farbe = 'rot');

select lnr, lname
     , (select count(*) from lt where lt.lnr = l.lnr) "#lieferungen"
  from l;

-- NICHT korreliert: innere Abfrage unabhängig
select lnr, lname from l
 where lnr in (select lnr from lt);

-- KORRELIERT: lt.lnr = l.lnr, l von außen
select lnr, lname from l
 where exists (select * from lt where lt.lnr = l.lnr);

select lnr, lname from l
 where not exists (
   select * from lt where lt.lnr = l.lnr
);

select l.lnr, l.lname from l
 where exists (select * from lt where lt.lnr = l.lnr and lt.tnr = 'T1')
   and exists (select * from lt where lt.lnr = l.lnr and lt.tnr = 'T2');

-- FALSCH: immer leer
select lnr from lt where tnr = 'T1' and tnr = 'T2';

-- KORREKT mit IN:
select lnr, lname from l
 where lnr in (select lnr from lt where tnr = 'T1')
   and lnr in (select lnr from lt where tnr = 'T2');

-- KORREKT mit EXISTS:
select l.lnr, l.lname from l
 where exists (select * from lt where lt.lnr = l.lnr and lt.tnr = 'T1')
   and exists (select * from lt where lt.lnr = l.lnr and lt.tnr = 'T2');

-- > ALL: nur Teile teurer als 19 (Maximum der roten Preise)
select * from t where preis > all (select preis from t where farbe = 'rot');

-- > SOME: alle Teile teurer als 12 (Minimum der roten Preise)
select * from t where preis > some (select preis from t where farbe = 'rot');

-- MAX-Variante (identisch mit ALL):
select * from t where preis > (select max(preis) from t where farbe = 'rot');

-- < ALL: Teile billiger als das BILLIGSTE rote Teil (< 12)
select * from t where preis < all (select preis from t where farbe = 'rot');

-- < SOME: Teile billiger als das TEUERSTE rote Teil (< 19)
select * from t where preis < some (select preis from t where farbe = 'rot');

-- INNER JOIN: Lieferanten ohne Lieferungen fehlen
select l.lnr, l.lname, lt.tnr from l
  join lt on l.lnr = lt.lnr;

-- LEFT JOIN: alle Lieferanten, fehlende Daten als NULL
select l.lnr, l.lname, lt.tnr from l
  left join lt on l.lnr = lt.lnr;

select t.tnr, t.tname from t
  left join lt on t.tnr = lt.tnr
 where lt.tnr is null;

(select lnr from lt where tnr = 'T1')
intersect
(select lnr from lt where tnr = 'T2');

-- FALSCH: liefert nie Ergebnisse
select * from l where stadt = NULL;

-- KORREKT:
select * from l where stadt is null;
select * from l where stadt is not null;

-- Wenn lt.lnr einen NULL-Eintrag hat, scheitert NOT IN:
select lnr, lname from l
 where lnr not in (select lnr from lt);

-- SICHER:
select l.lnr, l.lname from l
 where not exists (select * from lt where lt.lnr = l.lnr);

-- IMMER LEER:
select lnr from lt where tnr='T1' and tnr='T2';
-- KORREKT:
select lnr from l
 where lnr in (select lnr from lt where tnr='T1')
   and lnr in (select lnr from lt where tnr='T2');
